    def _token_start_positions(self, tokens: Sequence[int]) -> list[int]:
        """Computes the starting character position of each token in the original text.

        This assumes `tokens` were produced by encoding a string, so that concatenating the
        decoded bytes of each token and decoding as UTF-8 reconstructs that string.
        """
        text_len = 0
        positions = []
        for token in tokens:
            token_bytes = self.decode_single_token_bytes(token)
            positions.append(max(0, text_len - (0x80 <= token_bytes[0] < 0xC0)))
